  chain: "base";
  risk: number;
  strategies: string[];
  skills: string[];
}

export interface SpawnQuote {
  sessionId: string;
  chain: "base";
  asset: SpawnAsset;
  grossAmount: string;
  platformFee: string;
  creationCost: string;
  netForwardAmount: string;
  quoteTermsHash: string;
  expiresAt: number;
  paymentAddress: string;
}

export interface SpawnSession {
  sessionId: string;
  stewardAddress: string;
  chain: "base";
  asset: SpawnAsset;
  grossAmount: string;
  platformFee: string;
  creationCost: string;
  netForwardAmount: string;
  quoteTermsHash: string;
  expiresAt: number;
  state: SpawnSessionState;
  retryable: boolean;
  refundable: boolean;
  paymentStatus: PaymentStatus;
  automatonCanisterId: string | null;
  automatonEvmAddress: string | null;
  parentId: string | null;
  config: SpawnConfig;
  createdAt: number;
  updatedAt: number;
}

export interface CreateSpawnSessionRequest {
  stewardAddress: string;
  asset: SpawnAsset;
  grossAmount: string;
  config: SpawnConfig;
  parentId?: string | null;
}

export interface RetrySpawnRequest {
