}

export interface RefundSpawnRequest {
  sessionId: string;
}

export interface SpawnedAutomatonRecord {
  canisterId: string;
  stewardAddress: string;
  evmAddress: string;
  chain: "base";
  sessionId: string;
  parentId: string | null;
  createdAt: number;
  versionCommit: string;
}

export const SUPPORTED_CHAIN_SLUGS = [
  "base",
  "ethereum",
  "arbitrum",
  "optimism",
  "polygon"
] as const;

export const AUTOMATON_TIERS = [
  "normal",
  "low",
  "critical",
  "out_of_cycles"
] as const;

export type ChainSlug = (typeof SUPPORTED_CHAIN_SLUGS)[number];
export type AutomatonTier = (typeof AUTOMATON_TIERS)[number];

export interface GridPosition {
  x: number;
