import type { AutomatonSummary, MonologueEntry } from "./automaton.js";
import type { SpawnSession } from "./spawn.js";

export const AUTOMATON_EVENT_TYPES = [
  "automaton.snapshot.updated",
  "automaton.spawned",
  "automaton.message",
  "automaton.action"
] as const;

export const SPAWN_EVENT_TYPES = [
  "spawn.session.updated",
  "spawn.session.completed",
  "spawn.session.failed"
] as const;

export type AutomatonEventType = (typeof AUTOMATON_EVENT_TYPES)[number];
export type SpawnEventType = (typeof SPAWN_EVENT_TYPES)[number];

export interface AutomatonSnapshotUpdatedEvent {
  type: "automaton.snapshot.updated";
  automaton: AutomatonSummary;
}

export interface AutomatonSpawnedEvent {
  type: "automaton.spawned";
  automaton: AutomatonSummary;
}

export interface AutomatonMessageEvent {
  type: "automaton.message";
  canisterId: string;
  entry: MonologueEntry;
}

export interface AutomatonActionEvent {
  type: "automaton.action";
  canisterId: string;
  description: string;
  occurredAt: number;
}

export interface SpawnSessionUpdatedEvent {
  type: "spawn.session.updated" | "spawn.session.completed" | "spawn.session.failed";
  session: SpawnSession;
}

export type RealtimeEvent =
  | AutomatonSnapshotUpdatedEvent
  | AutomatonSpawnedEvent
  | AutomatonMessageEvent
  | AutomatonActionEvent
  | SpawnSessionUpdatedEvent;

export const CATALOG_ENTRY_STATUSES = [
  "available",
  "coming_soon"
] as const;

export type CatalogEntryStatus = (typeof CATALOG_ENTRY_STATUSES)[number];

export interface StrategyCatalogEntry {
  id: string;
  name: string;
  description: string;
  supportedChains: string[];
  riskLevel: 1 | 2 | 3 | 4 | 5;
  performanceLabel: string | null;
  status: CatalogEntryStatus;
}

export interface SkillCatalogEntry {
  id: string;
  name: string;
  description: string;
  dependencies: string[];
  category: string;
  status: CatalogEntryStatus;
}

export interface CatalogResponse<TEntry> {
  items: TEntry[];
  updatedAt: number;
}

import { describe, expect, it } from "vitest";

import { AUTOMATON_TIERS } from "../src/automaton.js";
import { CATALOG_ENTRY_STATUSES } from "../src/catalog.js";
import {
  AUTOMATON_EVENT_TYPES,
  SPAWN_EVENT_TYPES
} from "../src/events.js";
import {
  MINIMUM_GROSS_PAYMENT_USD,
  PAYMENT_STATUSES,
  SPAWN_SESSION_STATES,
  SUPPORTED_SPAWN_ASSETS
} from "../src/spawn.js";

describe("shared contracts", () => {
  it("tracks the locked spawn session lifecycle", () => {
    expect(SPAWN_SESSION_STATES).toEqual([
      "awaiting_payment",
      "payment_detected",
      "spawning",
      "funding_automaton",
      "complete",
      "failed",
      "expired"
    ]);
  });

  it("keeps the minimum gross payment floor at fifty dollars", () => {
    expect(MINIMUM_GROSS_PAYMENT_USD).toBe(50);
    expect(SUPPORTED_SPAWN_ASSETS).toEqual(["eth", "usdc"]);
    expect(PAYMENT_STATUSES).toEqual(["unpaid", "partial", "paid", "refunded"]);
  });

  it("exposes stable automaton and catalog enums", () => {
    expect(AUTOMATON_TIERS).toEqual([
      "normal",
      "low",
      "critical",
      "out_of_cycles"
    ]);
    expect(CATALOG_ENTRY_STATUSES).toEqual(["available", "coming_soon"]);
  });

  it("defines the baseline realtime event names", () => {
    expect(AUTOMATON_EVENT_TYPES).toContain("automaton.spawned");
    expect(SPAWN_EVENT_TYPES).toContain("spawn.session.updated");
  });
});

